import React from 'react'
import ServiceCard from './ServiceCard';
import {Col} from 'reactstrap';
import weatherImg from '../assets/images/weather.png'
import guideImg from '../assets/images/guide.png'
import customizationImg from '../assets/images/customization.png'
const servicesData =[
  {
  imgUrl:weatherImg,
  title:'Calculate Weather',
  desc:'Weather is calculated using a variety of data , including synoptic and climateological and surface observations.'
  },
  {
    imgUrl:guideImg,
    title:'Best Tour Guide',
    desc:'We avail the best guides that take groups around the places of interest.they also educates the visitors about places.'
  },
  {
    imgUrl:customizationImg,
    title:'Customization',
    desc:'We have arranged personalized tours  to create an itinerary  to each traveler, offering a more authentic travel experience .',
  },

]
const ServiceList = () => {
  return <>
      {
        servicesData.map((item,index)=>( 
        <Col lg='3'  key={index}>
          <ServiceCard item={item}/>
           </Col>
      ))}
    </>
  
}

export default ServiceList
